const pages = $input.first().json.pages || [];

const fileName = JSON.parse($('문서 카테고리 분류').first().json.output).fileName || 'unknown';

const result = [];

const CHUNK_SIZE = 6;
const OVERLAP = 2;    // 다음 묶음이랑 2줄은 겹치게 함 (문맥 끊김 방지)

const STEP = CHUNK_SIZE - OVERLAP;

for (const page of pages) {
  if (!page.markdown) continue;

  const lines = page.markdown
    .split('\n')
    .map(line => line.replace(/\|/g, ' ').trim())
    .filter(line => line.length > 0);

  for (let i = 0; i < lines.length; i += STEP) {
    const chunkLines = lines.slice(i, i + CHUNK_SIZE);

    const cleanContent = chunkLines.join(' ')
        .replace(/!\[.*?\]\(.*?\)/g, '') // 이미지 태그 제거
        .replace(/\[.*?\]\(.*?\)/g, '')  // 링크 텍스트만 남기고 경로 제거
        .replace(/\s+/g, ' ')            // 중복 공백 제거
        .trim();

    if (cleanContent.length === 0) continue;

    result.push({
      json: {
        content: cleanContent,
        fileName: fileName,
        lineIndex: page.index
      }
    });
  }
}

return result;

const splitData = $('split').all();
const categoryRaw = $('문서 카테고리 분류').item.json.output;
const categoryName = JSON.parse(categoryRaw.replace(/```json|```/g, '')).tableName;

// 현재 날짜 (YYYY-MM-DD) 생성
const today = new Date().toISOString().split('T')[0];

// Cypher 쿼리 문법 에러를 막기 위한 이스케이프 함수 (따옴표, 줄바꿈 등 처리)
const escapeCypher = (str) => {
  return (str || '')
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "\\'")
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r');
};

const cypherDataList = $input.all().map((item, index) => {
  const original = splitData[index].json;

  const safeFileName = escapeCypher(original.fileName);
  const safeContent = escapeCypher(original.content);
  const safeCategory = escapeCypher(categoryName);
  const lineIndex = original.lineIndex || 0;

  const embeddingStr = item.json.embedding.values.join(',');

  // Neo4j가 인식할 수 있는 Map(객체) 형태로 텍스트 조립
  return `{ fileName: '${safeFileName}', category: '${safeCategory}', date: '${today}', content: '${safeContent}', lineIndex: ${lineIndex}, embedding: [${embeddingStr}] }`;
});

// 전체 UNWIND 쿼리 문자열 조립 (데이터가 쿼리 안에 아예 하드코딩 되어 들어갑니다)
const finalQuery = `
// 1. 관계 노드 생성/확인 (이미 있으면 가져옴)
MERGE (cat:Category {name: '${escapeCypher(categoryName)}'})
MERGE (dNode:Date {date: '${today}'})

WITH cat, dNode
UNWIND [ ${cypherDataList.join(',\n  ')} ] AS item

// 2. 상위 노드 생성
MERGE (d:Document {fileName: item.fileName})
ON CREATE SET d.createdAt = datetime()
SET d.category = item.category, d.updatedAt = datetime()

// 3. 상위 노드에 관계 노드 연결(카테고리, 날짜)
MERGE (d)-[:IN_CATEGORY]->(cat)  
MERGE (d)-[:CREATED_ON]->(dNode)

// 4. 하위 청크 노드 생성 및 연결
CREATE (c:Chunk {
    content: item.content,
    lineIndex: item.lineIndex,
    embedding: item.embedding
})
MERGE (d)-[:HAS_CHUNK]->(c)

RETURN count(c) as totalInserted
`;

// 다음 노드로 완성된 'query' 텍스트 하나만 넘깁니다.
return [{
  json: {
    query: finalQuery
  }
}];

